public enum FfiError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    /**
     * Auth-layer error (`OpenSecret` or local session handling).
     */
    case Auth(code: UInt32, message: String
    )
    /**
     * Storage-layer error (Supabase REST + `postgrest`).
     */
    case Storage(code: UInt32, message: String
    )
    /**
     * Internal / programmer-error / FFI plumbing failure.
     */
    case Internal(message: String
    )

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension FfiError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiError: FfiConverterRustBuffer {
    typealias SwiftType = FfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Auth(
            code: try FfiConverterUInt32.read(from: &buf), 
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Storage(
            code: try FfiConverterUInt32.read(from: &buf), 
